def main():
    n, k = map(int, input().split())
    a = list(map(int, input().split()))
    dp = [[-1] * 6 for _ in range(n + 1)]
    dp[0][0] = 1
    for i in range(n):
        for j in range(6):
            if dp[i][j] == -1:
                continue
            for l in range(6):
                if a[i] + j + l <= k:
                    dp[i + 1][l] = max(dp[i + 1][l], dp[i][j] * (a[i] + j + l == 0))
    print(dp[n][0])


if __name__ == '__main__':
    main()
